import React, { useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { addEnquiry, updateEnquiryStatus, convertEnquiryToRegistration } from '../store/slices/admissionSlice';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';

const STATUS_CONFIG = {
  hot:       { bg:'#FEE2E2', c:'#991B1B', label:'🔥 Hot Lead'  },
  warm:      { bg:'#FEF3C7', c:'#92400E', label:'🌡️ Warm'      },
  cold:      { bg:'#DBEAFE', c:'#1E40AF', label:'🧊 Cold Lead'  },
  converted: { bg:'#D1FAE5', c:'#065F46', label:'✅ Converted'  },
};

const inp = { width:'100%', padding:'10px 12px', border:'1.5px solid #E5E7EB', borderRadius:9, fontSize:13, outline:'none', fontFamily:'inherit', background:'#fff', boxSizing:'border-box' };
const lbl = { display:'block', fontSize:11, fontWeight:700, color:'#4B5563', textTransform:'uppercase', letterSpacing:'.06em', marginBottom:6 };

const CLASSES = ['Class 1','Class 2','Class 3','Class 4','Class 5','Class 6','Class 7','Class 8','Class 9','Class 10','Class 11','Class 12'];

export default function Enquiry() {
  const dispatch    = useDispatch();
  const navigate    = useNavigate();
  const enquiries   = useSelector(s => s.admission.enquiries);
  const [showAdd,   setShowAdd]   = useState(false);
  const [selected,  setSelected]  = useState(null);
  const [filter,    setFilter]    = useState('');
  const [search,    setSearch]    = useState('');
  const [form, setForm] = useState({ name:'', parent:'', phone:'', email:'', class_:'', source:'Walk-in', remarks:'', status:'warm' });

  const filtered = enquiries.filter(e =>
    (!filter || e.status === filter) &&
    (!search || e.name.toLowerCase().includes(search.toLowerCase()) || e.phone.includes(search))
  );

  const handleAdd = (ev) => {
    ev.preventDefault();
    dispatch(addEnquiry(form));
    toast.success(`✅ Enquiry created for ${form.name}`);
    setShowAdd(false);
    setForm({ name:'', parent:'', phone:'', email:'', class_:'', source:'Walk-in', remarks:'', status:'warm' });
  };

  const handleConvert = (enq) => {
    dispatch(convertEnquiryToRegistration(enq.id));
    toast.success(`✅ ${enq.name} converted to Registration! Check Registration module.`);
    setSelected(null);
    setTimeout(() => navigate('/registration'), 1200);
  };

  const counts = Object.fromEntries(Object.keys(STATUS_CONFIG).map(k => [k, enquiries.filter(e => e.status === k).length]));

  return (
    <div>
      {/* Header */}
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:18}}>
        <div>
          <h2 style={{fontSize:20,fontWeight:700,color:'#111827'}}>Enquiry Management</h2>
          <p style={{fontSize:12,color:'#6B7280',marginTop:2}}>Track and convert leads — Enquiry → Registration → Admission</p>
        </div>
        <button onClick={()=>setShowAdd(true)} style={{padding:'9px 20px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>+ New Enquiry</button>
      </div>

      {/* Pipeline banner */}
      <div style={{display:'flex',alignItems:'center',gap:8,padding:'12px 16px',background:'#EDE9F8',borderRadius:12,marginBottom:16,fontSize:12,color:'#1E1B4B',fontWeight:600}}>
        <span>📞 Enquiry</span>
        <span style={{color:'#A78BFA',fontSize:16}}>→</span>
        <span>📄 Registration</span>
        <span style={{color:'#A78BFA',fontSize:16}}>→</span>
        <span>🎓 Admission</span>
        <span style={{marginLeft:'auto',fontSize:11,fontWeight:500,color:'#6B52B0'}}>Click "Convert to Registration" on any hot/warm lead</span>
      </div>

      {/* Status filters */}
      <div style={{display:'flex',gap:10,marginBottom:14,flexWrap:'wrap',alignItems:'center'}}>
        <input placeholder="🔍 Search name or phone…" value={search} onChange={e=>setSearch(e.target.value)}
          style={{...inp,maxWidth:240,flex:1}}/>
        {Object.entries(STATUS_CONFIG).map(([key,{bg,c,label}]) => (
          <div key={key} onClick={()=>setFilter(filter===key?'':key)}
            style={{padding:'7px 14px',borderRadius:20,background:filter===key?c:bg,color:filter===key?'#fff':c,fontSize:12,fontWeight:700,cursor:'pointer',border:`1.5px solid ${c}33`,userSelect:'none'}}>
            {label} ({counts[key]||0})
          </div>
        ))}
      </div>

      {/* Table */}
      <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden'}}>
        <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
          <thead><tr style={{background:'#F9FAFB'}}>
            {['Enq No','Student Name','Parent / Phone','Class','Source','Date','Lead Status','Change Status','Actions'].map(h=>(
              <th key={h} style={{padding:'10px 12px',textAlign:'left',color:'#6B7280',fontSize:10,fontWeight:700,textTransform:'uppercase',borderBottom:'1px solid #E5E7EB',whiteSpace:'nowrap'}}>{h}</th>
            ))}
          </tr></thead>
          <tbody>
            {filtered.length === 0 && (
              <tr><td colSpan={9} style={{padding:40,textAlign:'center',color:'#9CA3AF'}}>
                <div style={{fontSize:32,marginBottom:8}}>📞</div>
                No enquiries found
              </td></tr>
            )}
            {filtered.map(e => {
              const st = STATUS_CONFIG[e.status] || STATUS_CONFIG.warm;
              return (
                <tr key={e.id} style={{borderBottom:'0.5px solid #F3F4F6',transition:'background .1s'}}
                  onMouseEnter={ev=>ev.currentTarget.style.background='#F5F3FF'}
                  onMouseLeave={ev=>ev.currentTarget.style.background=''}>
                  <td style={{padding:'10px 12px',fontFamily:'monospace',fontSize:11,color:'#9CA3AF'}}>{e.no}</td>
                  <td style={{padding:'10px 12px',fontWeight:700,color:'#111827'}}>{e.name}</td>
                  <td style={{padding:'10px 12px'}}><div style={{fontWeight:500}}>{e.parent}</div><div style={{fontSize:10,color:'#9CA3AF'}}>{e.phone}</div></td>
                  <td style={{padding:'10px 12px',color:'#6B7280'}}>{e.class_||'—'}</td>
                  <td style={{padding:'10px 12px'}}><span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:'#EDE9F8',color:'#1E1B4B',fontWeight:600}}>{e.source}</span></td>
                  <td style={{padding:'10px 12px',color:'#6B7280'}}>{e.date}</td>
                  <td style={{padding:'10px 12px'}}><span style={{padding:'4px 10px',borderRadius:20,fontSize:11,fontWeight:700,background:st.bg,color:st.c}}>{st.label}</span></td>
                  <td style={{padding:'10px 12px'}}>
                    {e.status !== 'converted' ? (
                      <select value={e.status} onChange={ev=>{dispatch(updateEnquiryStatus({id:e.id,status:ev.target.value}));toast.success('Status updated');}}
                        style={{padding:'5px 8px',border:'1px solid #E5E7EB',borderRadius:7,fontSize:11,cursor:'pointer',background:'#fff',outline:'none'}}>
                        <option value="hot">🔥 Hot</option>
                        <option value="warm">🌡️ Warm</option>
                        <option value="cold">🧊 Cold</option>
                      </select>
                    ) : <span style={{fontSize:11,color:'#9CA3AF'}}>Converted</span>}
                  </td>
                  <td style={{padding:'10px 12px'}}>
                    <button onClick={()=>setSelected(e)}
                      style={{padding:'5px 12px',border:'1px solid #1E1B4B',borderRadius:7,background:'#EDE9F8',color:'#1E1B4B',fontSize:11,fontWeight:600,cursor:'pointer',whiteSpace:'nowrap'}}>
                      View Details
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        <div style={{padding:'10px 14px',borderTop:'0.5px solid #E5E7EB',fontSize:11,color:'#6B7280'}}>
          {filtered.length} enquiries shown · {counts.converted||0} converted to registration
        </div>
      </div>

      {/* Detail Panel */}
      {selected && (
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:400,display:'flex',alignItems:'center',justifyContent:'center',padding:20}}>
          <div style={{background:'#fff',borderRadius:18,width:500,maxHeight:'90vh',overflow:'auto'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center',position:'sticky',top:0,background:'#fff'}}>
              <div style={{fontWeight:700,fontSize:15}}>📋 Enquiry Details — {selected.no}</div>
              <button onClick={()=>setSelected(null)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <div style={{padding:22}}>
              {/* Status badge */}
              <div style={{padding:'12px 16px',background:STATUS_CONFIG[selected.status]?.bg,borderRadius:12,marginBottom:18,display:'flex',alignItems:'center',justifyContent:'space-between'}}>
                <span style={{fontWeight:700,color:STATUS_CONFIG[selected.status]?.c,fontSize:14}}>{STATUS_CONFIG[selected.status]?.label}</span>
                <span style={{fontSize:11,color:STATUS_CONFIG[selected.status]?.c}}>Enquiry #{selected.no}</span>
              </div>

              {/* Info grid */}
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:18}}>
                {[['Student',selected.name],['Parent/Guardian',selected.parent],['Mobile',selected.phone],['Email',selected.email||'—'],['Class Interested',selected.class_||'—'],['Source',selected.source],['Enquiry Date',selected.date],['Status',STATUS_CONFIG[selected.status]?.label]].map(([k,v])=>(
                  <div key={k} style={{padding:'10px 12px',background:'#F9FAFB',borderRadius:9}}>
                    <div style={{fontSize:10,color:'#9CA3AF',fontWeight:700,textTransform:'uppercase',letterSpacing:'.06em',marginBottom:4}}>{k}</div>
                    <div style={{fontSize:13,fontWeight:600,color:'#111827'}}>{v}</div>
                  </div>
                ))}
              </div>

              {/* Remarks */}
              {selected.remarks && (
                <div style={{padding:'12px 14px',background:'#FEF3C7',borderRadius:10,marginBottom:18,fontSize:13,color:'#92400E'}}>
                  <div style={{fontWeight:700,marginBottom:4,fontSize:11,textTransform:'uppercase',letterSpacing:'.06em'}}>Remarks</div>
                  {selected.remarks}
                </div>
              )}

              {/* Actions */}
              {selected.status !== 'converted' ? (
                <div style={{display:'flex',gap:10}}>
                  <button onClick={()=>handleConvert(selected)}
                    style={{flex:1,padding:'12px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:10,fontSize:13,fontWeight:700,cursor:'pointer'}}>
                    📄 Convert to Registration →
                  </button>
                  <button onClick={()=>{toast.success('Follow-up scheduled!');setSelected(null);}}
                    style={{padding:'12px 16px',border:'1.5px solid #E5E7EB',borderRadius:10,background:'#fff',fontSize:13,cursor:'pointer'}}>
                    📅 Follow-up
                  </button>
                </div>
              ) : (
                <div style={{padding:'14px',background:'#D1FAE5',borderRadius:10,textAlign:'center',color:'#065F46',fontWeight:600,fontSize:13}}>
                  ✅ Already converted to Registration
                  <button onClick={()=>{navigate('/registration');setSelected(null);}} style={{display:'block',margin:'8px auto 0',padding:'6px 16px',background:'#065F46',color:'#fff',border:'none',borderRadius:7,fontSize:12,cursor:'pointer'}}>View in Registration →</button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Add Enquiry Modal */}
      {showAdd && (
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:500,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}>
          <div style={{background:'#fff',borderRadius:18,width:520,maxWidth:'100%',maxHeight:'90vh',overflow:'auto'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center',position:'sticky',top:0,background:'#fff'}}>
              <div style={{fontWeight:700,fontSize:15}}>📞 New Enquiry</div>
              <button onClick={()=>setShowAdd(false)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <form onSubmit={handleAdd} style={{padding:20}}>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Student Name *</label><input required value={form.name} onChange={e=>setForm({...form,name:e.target.value})} placeholder="Student full name" style={inp} autoFocus/></div>
                <div><label style={lbl}>Parent/Guardian *</label><input required value={form.parent} onChange={e=>setForm({...form,parent:e.target.value})} placeholder="Parent name" style={inp}/></div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Mobile *</label><input required value={form.phone} onChange={e=>setForm({...form,phone:e.target.value})} placeholder="10-digit" style={inp} maxLength={10}/></div>
                <div><label style={lbl}>Email</label><input type="email" value={form.email} onChange={e=>setForm({...form,email:e.target.value})} placeholder="optional" style={inp}/></div>
                <div><label style={lbl}>Class Interested</label>
                  <select value={form.class_} onChange={e=>setForm({...form,class_:e.target.value})} style={inp}>
                    <option value="">Select</option>{CLASSES.map(c=><option key={c}>{c}</option>)}
                  </select>
                </div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Source</label>
                  <select value={form.source} onChange={e=>setForm({...form,source:e.target.value})} style={inp}>
                    {['Walk-in','Phone','Website','Reference','Social Media','Newspaper'].map(s=><option key={s}>{s}</option>)}
                  </select>
                </div>
                <div><label style={lbl}>Lead Status</label>
                  <select value={form.status} onChange={e=>setForm({...form,status:e.target.value})} style={inp}>
                    <option value="hot">🔥 Hot Lead</option>
                    <option value="warm">🌡️ Warm Lead</option>
                    <option value="cold">🧊 Cold Lead</option>
                  </select>
                </div>
              </div>
              <div style={{marginBottom:16}}><label style={lbl}>Remarks / Notes</label><textarea value={form.remarks} onChange={e=>setForm({...form,remarks:e.target.value})} placeholder="Any notes about this enquiry…" rows={3} style={{...inp,resize:'vertical'}}/></div>
              <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
                <button type="button" onClick={()=>setShowAdd(false)} style={{padding:'10px 18px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button type="submit" style={{padding:'10px 24px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>💾 Save Enquiry</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
